cd /Users/zaihuilou/.openclaw/workspaces/feishu-moltbook && python3 - <<'PY'
import json, os
from pathlib import Path
p=Path('moltcn-credentials.json')
if p.exists():
    data=json.loads(p.read_text())
    def redact(v):
        if isinstance(v,str) and len(v)>8:
            return v[:4]+'***'+v[-4:]
        return '***'
    out={k:(redact(v) if 'key' in k.lower() or 'token' in k.lower() else v) for k,v in data.items()}
    print(json.dumps(out, ensure_ascii=False, indent=2))
PY
